// Format escalation message with inline keyboard for Telegram
const body = $json.body || $json;
const type = body.type || 'unknown';
const issueKey = body.issueKey || 'N/A';
const agent = body.agent || 'unknown';
const reason = body.reason || 'No reason provided';
const options = body.options || {};
const meetingId = body.meetingId || null;

// Generate a unique escalation ID
const escId = `${issueKey}-${Date.now()}`;

// Type-specific icon and label
const typeConfig = {
  'budget-exceeded': { icon: '[BUDGET]', label: 'Budget Exceeded' },
  'security-critical': { icon: '[SECURITY]', label: 'Security Critical' },
  'architecture-change': { icon: '[ARCH]', label: 'Architecture Change' },
  'customer-facing': { icon: '[CUSTOMER]', label: 'Customer-Facing Change' },
  'priority-override': { icon: '[PRIORITY]', label: 'Priority Override' }
};

const config = typeConfig[type] || { icon: '[ESCALATION]', label: type };

// Build the message text
let messageText = `${config.icon} *Escalation: ${config.label}*\n\n`;
messageText += `*Issue*: ${issueKey}\n`;
messageText += `*Agent*: ${agent}\n`;
messageText += `*Reason*: ${reason}\n`;

if (options.currentCost) {
  messageText += `*Current Cost*: $${options.currentCost}\n`;
}
if (options.requestedBudget) {
  messageText += `*Requested Budget*: $${options.requestedBudget}\n`;
}
if (options.affectedFiles) {
  messageText += `*Affected Files*: ${Array.isArray(options.affectedFiles) ? options.affectedFiles.join(', ') : options.affectedFiles}\n`;
}
if (options.riskLevel) {
  messageText += `*Risk Level*: ${options.riskLevel}\n`;
}
if (meetingId) {
  messageText += `*Meeting*: ${meetingId}\n`;
}

messageText += `\n*Time*: ${new Date().toISOString().replace('T', ' ').substring(0, 19)} UTC`;

// Build inline keyboard JSON for reply_markup
const replyMarkup = JSON.stringify({
  inline_keyboard: [
    [
      { text: 'Approve', callback_data: `esc_approve_${escId}` },
      { text: 'Reject', callback_data: `esc_reject_${escId}` },
      { text: 'Defer', callback_data: `esc_defer_${escId}` }
    ]
  ]
});

return [{
  json: {
    escId,
    type,
    issueKey,
    agent,
    reason,
    messageText,
    replyMarkup
  }
}];

// Meshwork webhook caller verification.
// Accepts EITHER:
//   1) the runner's HMAC signature (x-meshwork-signature over `${ts}.${body}`)
//   2) a shared token in ?token= or the x-webhook-token header (for external
//      callers like Jira webhook URLs)
// Enforcement is off until WEBHOOK_VERIFICATION_ENFORCE=true in .env (values
// are substituted at import time by scripts/import-workflows.sh).
const crypto = require('crypto');

const ENFORCE = '{{WEBHOOK_VERIFICATION_ENFORCE}}'.toLowerCase() === 'true';
const RUNNER_SECRET = '{{RUNNER_SECRET}}';
const SHARED_TOKEN = '{{WEBHOOK_SHARED_TOKEN}}';

const item = $input.first().json;
const headers = item.headers || {};
const query = item.query || {};
const body = item.body ?? {};

const isPlaceholder = (v) => !v || v.indexOf('{{') === 0;
let ok = false;

// 1) Runner HMAC
const sig = headers['x-meshwork-signature'];
const ts = headers['x-meshwork-timestamp'];
if (sig && ts && !isPlaceholder(RUNNER_SECRET)) {
  const age = Math.abs(Date.now() - Number(ts));
  if (age < 5 * 60 * 1000) {
    const expected = 'sha256=' + crypto.createHmac('sha256', RUNNER_SECRET)
      .update(ts + '.' + JSON.stringify(body)).digest('hex');
    const a = crypto.createHash('sha256').update(expected).digest();
    const b = crypto.createHash('sha256').update(String(sig)).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

// 2) Shared token
if (!ok && !isPlaceholder(SHARED_TOKEN)) {
  const provided = String(query.token || headers['x-webhook-token'] || '');
  if (provided) {
    const a = crypto.createHash('sha256').update(provided).digest();
    const b = crypto.createHash('sha256').update(SHARED_TOKEN).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

if (!ok && ENFORCE) {
  throw new Error('Webhook verification failed: missing or invalid signature/token. See SECURITY.md (webhook verification).');
}

return $input.all();
